  // Guarantees section
  'guarantees.label': { en: 'GUARANTEES', fr: 'GARANTIES', hu: 'GARANCIÁK' },
  'guarantees.title': { en: 'Zero risk.', fr: 'Zéro risque.', hu: 'Nulla kockázat.' },
  'guarantees.titleAccent': { en: '7 guarantees.', fr: '7 garanties.', hu: '7 garancia.' },
  'guarantees.roi.title': { en: 'ROI Guarantee', fr: 'Garantie ROI', hu: 'ROI-garancia' },
  'guarantees.roi.desc': { en: 'We define a number together before starting. It\'s written in the contract. If at 12 months it\'s not reached, we work for free until it is.', fr: 'On définit ensemble un chiffre avant de commencer. Il est écrit dans le contrat. Si à 12 mois il n\'est pas atteint, on travaille gratuitement jusqu\'à ce qu\'il le soit.', hu: 'A kezdés előtt közösen meghatározunk egy számot. Ez bekerül a szerződésbe. Ha 12 hónap alatt nem éri el, ingyen dolgozunk addig, amíg el nem éri.' },
  'guarantees.delays.title': { en: 'Deadline Guarantee', fr: 'Garantie Délais', hu: 'Határidő-garancia' },
  'guarantees.delays.desc': { en: 'Each unjustified week of delay on the signed initial scope = -10% on the remaining balance, capped at 50%.', fr: 'Chaque semaine de retard injustifiée sur le périmètre initial signé = -10% sur le solde restant, plafonné à 50%. Ne compte pas : évolutions hors périmètre, retours clients non fournis sous 48h, RDV non honorés.', hu: 'Az aláírt kezdeti hatókörben minden indokolatlan csúszáshét = -10% a fennmaradó összegből, 50%-os plafonnal.' },
  'guarantees.ownership.title': { en: 'Ownership Guarantee', fr: 'Garantie Propriété', hu: 'Tulajdonjogi garancia' },
  'guarantees.ownership.desc': { en: '100% of the code belongs to you at delivery. No subscription to keep access. If NateSystem disappears tomorrow, your tool keeps running.', fr: '100% du code vous appartient à la livraison. Aucun abonnement pour garder l\'accès. Si NateSystem disparaît demain, votre outil tourne toujours.', hu: 'A kód 100%-a az Öné az átadáskor. Nincs előfizetés a hozzáférés megtartásához. Ha holnap eltűnik a NateSystem, az eszköze tovább működik.' },
  'guarantees.productivity.title': { en: 'Productivity Guarantee', fr: 'Garantie Productivité', hu: 'Termelékenységi garancia' },
  'guarantees.productivity.desc': { en: 'We measure together the time lost on targeted tasks before starting. If 90 days after delivery your team hasn\'t recovered at least 30% of that time — we continue for free.', fr: 'On mesure ensemble le temps perdu sur les tâches ciblées avant de commencer. Si 90 jours après livraison votre équipe n\'a pas récupéré au moins 30% de ce temps — on continue gratuitement jusqu\'à ce que ce soit le cas.', hu: 'A kezdés előtt közösen megmérjük a célzott feladatokra pazarolt időt. Ha 90 nappal az átadás után a csapata nem nyeri vissza ebből legalább 30%-ot — ingyen folytatjuk.' },
  'guarantees.efficiency.title': { en: 'Efficiency Guarantee', fr: 'Garantie Efficacité', hu: 'Hatékonysági garancia' },
  'guarantees.efficiency.desc': { en: 'We identify together before launch the recurring operational errors the infrastructure must eliminate. If 90 days after delivery these errors still exist — we fix them for free until zero.', fr: 'On identifie ensemble avant démarrage les erreurs opérationnelles récurrentes que l\'infrastructure doit éliminer. Si 90 jours après livraison ces erreurs existent encore — on corrige gratuitement jusqu\'à zéro.', hu: 'Az indulás előtt közösen azonosítjuk az ismétlődő működési hibákat, amelyeket az infrastruktúrának meg kell szüntetnie. Ha 90 nap múlva még léteznek — ingyen javítjuk, amíg nullára nem csökkennek.' },
  'guarantees.family.title': { en: 'The Family Guarantee', fr: 'La Garantie Famille', hu: 'A családi garancia' },
  'guarantees.family.desc': { en: 'Within 90 days of delivery, if you\'re not satisfied enough to talk about it at every family dinner until everyone is tired of hearing about it — dinner is on us.', fr: 'Dans les 90 jours suivant la livraison, si vous n\'êtes pas suffisamment satisfait pour en parler à chaque repas de famille jusqu\'à ce que tout le monde en soit lassé — on vous offre le restau.', hu: 'Az átadás utáni 90 napon belül, ha nem elég elégedett ahhoz, hogy minden családi vacsorán beszéljen róla, amíg mindenki meg nem unja — a vacsora a mi vendégünk.' },
  'guarantees.competitor.title': { en: 'The Competitor Guarantee', fr: 'La Garantie Concurrent', hu: 'A versenytárs-garancia' },
  'guarantees.competitor.desc': { en: 'Within 90 days of delivery, if you\'re not satisfied enough to beg us not to work with your direct competitor — dinner is on us.', fr: 'Dans les 90 jours suivant la livraison, si vous n\'êtes pas suffisamment satisfait pour nous supplier de ne pas travailler avec votre concurrent direct — on vous offre le restau.', hu: 'Az átadás utáni 90 napon belül, ha nem elég elégedett ahhoz, hogy könyörögjön nekünk: ne dolgozzunk a közvetlen versenytársával — a vacsora a mi vendégünk.' },
  'guarantees.absurdLabel': { en: 'OUR BET', fr: 'NOTRE PARI', hu: 'A FOGADÁSUNK' },

